// Description: Collects storage throughput, IOPS, and latency metrics for a KubeVirt VMI via Thanos Querier.
// Description: Uses executeQuery() helper and calculates latency from time/operation ratios.
import groovy.json.JsonSlurper
import javax.net.ssl.*
import java.security.cert.X509Certificate

def host = hostProps.get("openshift.thanos.host")
def token = hostProps.get("openshift.thanos.pass")
def port = hostProps.get("openshift.thanos.port") ?: "443"
def useSsl = (hostProps.get("openshift.thanos.ssl") ?: "true").toLowerCase() == "true"

def vmiName = instanceProps.get("auto.vmi.name")

if (!host || !token || !vmiName) {
    println("read_bytes:0")
    println("write_bytes:0")
    println("read_iops:0")
    println("write_iops:0")
    println("read_latency_ms:0")
    println("write_latency_ms:0")
    println("flush_requests:0")
    println("flush_latency_ms:0")
    return 0
}

def trustAllCerts = [
    checkClientTrusted: { chain, authType -> },
    checkServerTrusted: { chain, authType -> },
    getAcceptedIssuers: { null }
] as X509TrustManager

def sc = SSLContext.getInstance("TLS")
sc.init(null, [trustAllCerts] as TrustManager[], null)
HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory())
HttpsURLConnection.setDefaultHostnameVerifier({ hostname, session -> true } as HostnameVerifier)

def proto = useSsl ? "https" : "http"
def baseUrl = "${proto}://${host}:${port}"

def executeQuery(String promql, String baseUrl, String token) {
    try {
        def encoded = java.net.URLEncoder.encode(promql, "UTF-8")
        def url = new URL("${baseUrl}/api/v1/query?query=${encoded}")
        def conn = url.openConnection()
        conn.setRequestProperty("Authorization", "Bearer ${token}")
        conn.setConnectTimeout(30000)
        conn.setReadTimeout(30000)

        if (conn.responseCode == 200) {
            def response = conn.inputStream.text
            def json = new JsonSlurper().parseText(response)
            if (json.status == "success" && json.data?.result?.size() > 0) {
                def val = json.data.result[0].value[1]
                return val?.toString()?.isNumber() ? val : null
            }
        } else {
            System.err.println("Query failed: HTTP ${conn.responseCode} for: ${promql}")
        }
    } catch (Exception e) {
        System.err.println("Query error for ${promql}: ${e.message}")
    }
    return null
}

def queries = [
    "read_bytes": 'sum(rate(kubevirt_vmi_storage_read_traffic_bytes_total{name="' + vmiName + '"}[5m]))',
    "write_bytes": 'sum(rate(kubevirt_vmi_storage_write_traffic_bytes_total{name="' + vmiName + '"}[5m]))',
    "read_iops": 'sum(rate(kubevirt_vmi_storage_iops_read_total{name="' + vmiName + '"}[5m]))',
    "write_iops": 'sum(rate(kubevirt_vmi_storage_iops_write_total{name="' + vmiName + '"}[5m]))',
    "read_times": 'sum(rate(kubevirt_vmi_storage_read_times_seconds_total{name="' + vmiName + '"}[5m]))',
    "write_times": 'sum(rate(kubevirt_vmi_storage_write_times_seconds_total{name="' + vmiName + '"}[5m]))',
    "flush_requests": 'sum(rate(kubevirt_vmi_storage_flush_requests_total{name="' + vmiName + '"}[5m]))',
    "flush_times": 'sum(rate(kubevirt_vmi_storage_flush_times_seconds_total{name="' + vmiName + '"}[5m]))'
]

def raw = [:]
queries.each { k, q ->
    def val = executeQuery(q, baseUrl, token)
    raw[k] = val != null ? (val as Double) : 0
}

def readLatMs = raw["read_iops"] > 0 ? (raw["read_times"] / raw["read_iops"]) * 1000 : 0
def writeLatMs = raw["write_iops"] > 0 ? (raw["write_times"] / raw["write_iops"]) * 1000 : 0
def flushLatMs = raw["flush_requests"] > 0 ? (raw["flush_times"] / raw["flush_requests"]) * 1000 : 0

println("read_bytes:" + raw["read_bytes"])
println("write_bytes:" + raw["write_bytes"])
println("read_iops:" + raw["read_iops"])
println("write_iops:" + raw["write_iops"])
println("read_latency_ms:" + readLatMs)
println("write_latency_ms:" + writeLatMs)
println("flush_requests:" + raw["flush_requests"])
println("flush_latency_ms:" + flushLatMs)

return 0
